  2072→anti_adjust_stack_and_probe_stack_clash (rtx size)
  2073→{
  2074→  /* First ensure SIZE is Pmode.  */
  2075→  if (GET_MODE (size) != VOIDmode && GET_MODE (size) != Pmode)
  2076→    size = convert_to_mode (Pmode, size, 1);
