  2079→  rtx rounded_size, last_addr, residual;
  2080→  HOST_WIDE_INT probe_interval, probe_range;
  2081→  bool target_probe_range_p = false;
  2082→  compute_stack_clash_protection_loop_data (&rounded_size, &last_addr,
  2083→					    &residual, &probe_interval, size);
  2084→
  2085→  /* Get the back-end specific probe ranges.  */
  2086→  probe_range = targetm.stack_clash_protection_alloca_probe_range ();
  2087→  target_probe_range_p = probe_range != 0;
  2088→  gcc_assert (probe_range >= 0);
  2089→
  2090→  /* If no back-end specific range defined, default to the top of the newly
  2091→     allocated range.  */
  2092→  if (probe_range == 0)
  2093→    probe_range = probe_interval - GET_MODE_SIZE (word_mode);
